function StepStatusPill({
  tone,
  children,
}: {
  tone: "done" | "required" | "optional";
  children: React.ReactNode;
}) {
  const toneClass =
    tone === "done"
      ? "text-[var(--fg-positive)]"
      : tone === "required"
        ? "text-[var(--fg-warning)]"
        : "text-[var(--fg-secondary)]";

  return (
    <span
      className={`shrink-0 rounded-full bg-[var(--bg-hover)] px-2.5 py-0.5 text-xs font-medium ${toneClass}`}
    >
      {children}
    </span>
  );
}

